            try { return RunGpuCullDrawShowcase(out); }
            catch (const std::exception& e) { return fail(std::string("exception: ") + e.what()); }
        }
        // --cluster-cull <out.png>: render the virtual-geometry per-CLUSTER frustum cull showcase (Slice DT:
        // GPU per-cluster cull -> indirect cluster draw). The TRUE pass (a compute shader cluster_cull.comp
        // frustum-culls the (instance x cluster) records + ORDER-compacts the survivors into the MDI command
        // buffer + the compacted per-draw SSBO + writes the survivor count, then ONE DrawIndexedMultiIndirect
        // over cluster_viz.vert + meshlet_viz.frag renders exactly the surviving cluster-instances) is the
        // VULKAN demonstration (--cluster-cull-shot); here Metal renders the IDENTICAL instance grid of
        // DS-clustered spheres via the CPU per-cluster BOUND path (the SAME render::vg::CullClusterInstances
        // decides the survivors, drawn per-cluster via the meshlet_viz push-constant path in source order),
        // so cluster_cull.png is backend-identical to the Vulkan GPU-culled image. The cull frustum is built
        // from the SAME FlipProjY-composed view-proj the renderer uses (Metal clip). New golden
        // tests/golden/metal/cluster_cull.png; two runs DIFF 0.0000.
        if (argc > 1 && std::strcmp(argv[1], "--cluster-cull") == 0) {
            const char* out = argc > 2 ? argv[2] : "metal_cluster_cull.png";
            try { return RunClusterCullShowcase(out); }
            catch (const std::exception& e) { return fail(std::string("exception: ") + e.what()); }
        }
        // --visbuffer <out.png>: render the virtual-geometry VISIBILITY BUFFER showcase (Slice DW). The
        // TRUE Vulkan pass (the DT survivor cluster MDI draw rasterizing (clusterID<<7 | SV_PrimitiveID)
        // into an R32_Uint render target) is --visbuffer-shot; here Metal renders the IDENTICAL survivor
        // set via the per-cluster BOUND path (visbuffer_bound.vert pushes each survivor's clusterID; the
        // shared visbuffer.frag packs the (clusterID, SV_PrimitiveID) pair into the same R32_Uint RT). The
        // integer RT is ReadRenderTarget'd back into uint32[w*h] and PROVEN bit-exact (B1 self-consistent +
        // coverage, B2 determinism, B3 GPU==CPU instance provenance). The image golden is a CPU-coloring of
        // the read-back IDs (bg->clear, else hashColor(clusterID)), identical to the Vulkan path BY
        // CONSTRUCTION. New golden tests/golden/metal/visbuffer.png; two runs DIFF 0.0000.
        if (argc > 1 && std::strcmp(argv[1], "--visbuffer") == 0) {
            const char* out = argc > 2 ? argv[2] : "metal_visbuffer.png";
            try { return RunVisBufferShowcase(out); }
            catch (const std::exception& e) { return fail(std::string("exception: ") + e.what()); }
        }
        // --visresolve <out.png>: render the virtual-geometry DEFERRED MATERIAL RESOLVE showcase (Slice DX).
        // The TRUE Vulkan pass (--visresolve-shot: render the vis-buffer -> a fullscreen resolve pass
        // texel-fetches it + flat-shades the covering triangle) is mirrored here on Metal: the SAME survivor
        // set is rasterized into the SAME R32_Uint vis-buffer (per-cluster bound, == --visbuffer), then the
        // SAME visresolve.frag fullscreen pass texel-fetches it (BindTexture, no sampler — the integer
        // texture.read needs MSL 2.2) + the cluster-meta/index/vertex SSBOs (BindLightClusters) -> the lit
        // image. ID-provenance + GPU==CPU resolve-math bit-exact + determinism + a forward SMOKE bound. New
        // golden tests/golden/metal/visresolve.png; two runs DIFF 0.0000. NO new RHI.
        if (argc > 1 && std::strcmp(argv[1], "--visresolve") == 0) {
            const char* out = argc > 2 ? argv[2] : "metal_visresolve.png";
            try { return RunVisResolveShowcase(out); }
            catch (const std::exception& e) { return fail(std::string("exception: ") + e.what()); }
        }
